def iterative_dfs(graph, start):
    visited, stack = set(), [start]
    result = []
    while stack:
        node = stack.pop()
        if node not in visited:
            visited.add(node)
            result.append(node)
            for neighbor in reversed(graph[node]):
                stack.append(neighbor)
    return result

graph = {0: [1, 2], 1: [3], 2: [], 3: []}
print(iterative_dfs(graph, 0))  # [0, 1, 3, 2]

